/* eslint-disable */
// @ts-nocheck
/**
 * goose-game-engine.ts
 * 逆流鹅上 游戏引擎
 */

interface SkinDef {
    score: number;
    name: string;
}

interface SkinEntry extends SkinDef {
    img: HTMLImageElement | null;
}

interface GamePalette {
    riverBg: string;
    hudBg: string;
    cardBg: string;
    btnPrimary: string;
    btnShadow: string;
    btnAlpha: string;
    titleColor: string;
    textPrimary: string;
    textHint: string;
    textMuted: string;
    hintAlpha: string;
    divider: string;
    danger: string;
    dangerLight: string;
    gold: string;
    accent: string;
    overlayFaint: string;
    overlayMed: string;
}

export function initGooseGame(
    canvasEl: HTMLCanvasElement,
    skinDefs: SkinDef[],
    onGameOver?: () => void,
    onRetry?: () => void
): () => void {
    const canvas = canvasEl,
        ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
    // 获取顶部安全区域偏移
    const safeTop = (() => {
        const style = getComputedStyle(document.documentElement);
        // --sat 可能是 var(...) 格式，需要直接读 --safe-margin-top
        const smt = style.getPropertyValue('--safe-margin-top').trim();
        if (smt) return parseInt(smt);
        const pad = style.getPropertyValue('padding-top').trim();
        if (pad) return parseInt(pad);
        return 44;
    })();
    const TOP_O = safeTop + 20;
    console.warn(
        '[GooseGame] TOP_O =',
        TOP_O,
        'smt =',
        getComputedStyle(document.documentElement).getPropertyValue('--safe-margin-top')
    );
    function readPal(el: HTMLElement): GamePalette {
        const s = getComputedStyle(el);
        const g = (v: string) => s.getPropertyValue(v).trim();
        return {
            riverBg: g('--game-river-bg') || '#B8D8E8',
            hudBg: g('--game-hud-bg') || 'rgba(255,255,255,0.62)',
            cardBg: g('--game-card-bg') || 'rgba(255,255,255,0.93)',
            btnPrimary: g('--game-btn-primary') || '#7ECAA0',
            btnShadow: g('--game-btn-shadow') || 'rgba(60,120,90,0.18)',
            btnAlpha: g('--game-btn-alpha') || 'rgba(126,202,160,0.28)',
            titleColor: g('--game-title-color') || '#5AAA78',
            textPrimary: g('--game-text-primary') || '#445566',
            textHint: g('--game-text-hint') || '#778899',
            textMuted: g('--game-text-muted') || '#BBCCDD',
            hintAlpha: g('--game-hint-alpha') || 'rgba(80,110,100,0.4)',
            divider: g('--game-divider') || '#DDDDDD',
            danger: g('--game-danger') || '#E87060',
            dangerLight: g('--game-danger-light') || '#E88070',
            gold: g('--game-gold') || '#E8A050',
            accent: g('--game-accent') || '#2A8BAE',
            overlayFaint: g('--game-overlay-faint') || 'rgba(184,216,232,0.1)',
            overlayMed: g('--game-overlay-med') || 'rgba(184,216,232,0.28)'
        };
    }
    const pal = readPal(canvasEl.parentElement || canvasEl);
    const W = 400,
        BANK = 42,
        RL = BANK,
        RR = W - BANK,
        RW = RR - RL;
    let H = 750;
    let scale = 1;
    let centreX = 0;
    let logicalW = 400;
    const F = '"PingFang SC","Hiragino Sans GB","Microsoft YaHei",sans-serif';
    function rr(x, y, w, h, r) {
        r = Math.min(r, w / 2, h / 2);
        ctx.moveTo(x + r, y);
        ctx.lineTo(x + w - r, y);
        ctx.arcTo(x + w, y, x + w, y + r, r);
        ctx.lineTo(x + w, y + h - r);
        ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
        ctx.lineTo(x + r, y + h);
        ctx.arcTo(x, y + h, x, y + h - r, r);
        ctx.lineTo(x, y + r);
        ctx.arcTo(x, y, x + r, y, r);
        ctx.closePath();
    }
    function resize() {
        const ww = canvas.offsetWidth || innerWidth,
            wh = Math.max(canvas.offsetHeight || 0, innerHeight);
        const dpr = window.devicePixelRatio || 1;
        scale = ww / W;
        H = Math.round(wh / scale);
        const MIN_H = 620;
        if (H < MIN_H) {
            scale = wh / MIN_H;
            H = MIN_H;
            centreX = (ww / scale - W) / 2;
            logicalW = ww / scale;
        } else {
            centreX = 0;
            logicalW = W;
        }
        canvas.width = ww * dpr;
        canvas.height = wh * dpr;
        ctx.scale(dpr, dpr);
    }
    addEventListener('resize', resize);
    resize();
    let correctionRafId = requestAnimationFrame(resize);
    function svgImg(svg, w, h, cb) {
        const img = new Image();
        img.onload = () => cb(img);
        img.src =
            'data:image/svg+xml,' +
            encodeURIComponent(
                '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' + w + ' ' + h + '">' + svg + '</svg>'
            );
    }
    function pngImg(b64, cb) {
        const img = new Image();
        img.onload = () => cb(img);
        img.src = 'data:image/png;base64,' + b64;
    }
    const spr = {};
    let loadN = 0;
    const TOTAL = 11;
    function onLoad() {
        loadN++;
        if (loadN >= TOTAL) requestAnimationFrame(loop);
    }
    pngImg(
        '',
        img => {
            spr.goose = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            spr.shark = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            spr.croc = img;
            onLoad();
        }
    );
    svgImg(
        '<ellipse cx="40" cy="56" rx="28" ry="9" fill="#5A3D0A" opacity="0.25"/><rect x="14" y="22" width="52" height="34" rx="3" fill="#8B6914"/><rect x="16" y="24" width="48" height="30" rx="2" fill="#A07840"/><ellipse cx="40" cy="22" rx="26" ry="11" fill="#C49A6C"/><ellipse cx="40" cy="22" rx="20" ry="8.5" fill="none" stroke="#A07840" stroke-width="1.5" opacity="0.5"/><ellipse cx="40" cy="22" rx="14" ry="6" fill="none" stroke="#8B6914" stroke-width="1.2" opacity="0.4"/><ellipse cx="40" cy="22" rx="8" ry="3.5" fill="none" stroke="#6B4E14" stroke-width="1" opacity="0.4"/><ellipse cx="40" cy="22" rx="3" ry="1.3" fill="#5A3D0A" opacity="0.35"/><path d="M18,32 Q16,42 18,52" stroke="#6B4E14" stroke-width="1.5" fill="none" opacity="0.4" stroke-linecap="round"/><path d="M62,30 Q64,40 62,50" stroke="#6B4E14" stroke-width="1.5" fill="none" opacity="0.4" stroke-linecap="round"/><path d="M35,36 Q36,44 35,52" stroke="#6B4E14" stroke-width="1" fill="none" opacity="0.35" stroke-linecap="round"/>',
        80,
        65,
        img => {
            spr.stump = img;
            onLoad();
        }
    );
    svgImg(
        '<ellipse cx="35" cy="46" rx="25" ry="8" fill="#8890A0" opacity="0.28"/><path d="M11,36 Q13,18 35,15 Q57,13 59,32 Q61,48 35,50 Q11,50 11,36Z" fill="#AABACA"/><path d="M14,30 Q18,16 35,14 Q52,14 56,26 Q48,19 35,17 Q20,17 14,30Z" fill="#C0CCD8" opacity="0.8"/><ellipse cx="48" cy="38" rx="9" ry="5.5" fill="#98A8B8" opacity="0.45"/><ellipse cx="29" cy="22" rx="9" ry="5" fill="white" opacity="0.22"/>',
        70,
        55,
        img => {
            spr.rock = img;
            onLoad();
        }
    );
    const SKIN_DEFS: SkinEntry[] = skinDefs.map(s => ({
        score: s.score,
        name: s.name,
        img: null as HTMLImageElement | null
    }));
    pngImg(
        '',
        img => {
            SKIN_DEFS[0].img = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            SKIN_DEFS[1].img = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            SKIN_DEFS[2].img = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            SKIN_DEFS[3].img = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            SKIN_DEFS[4].img = img;
            onLoad();
        }
    );
    pngImg(
        '',
        img => {
            SKIN_DEFS[5].img = img;
            onLoad();
        }
    );

    const parts = [];
    function emitP(x, y, type, n) {
        for (let i = 0; i < n; i++) {
            const a = Math.random() * Math.PI * 2,
                sp = type === 'death' ? 1.5 + Math.random() * 3 : 0.3 + Math.random() * 0.5;
            parts.push({
                x,
                y,
                vx: Math.cos(a) * sp,
                vy: Math.sin(a) * sp,
                life: 1,
                decay: type === 'death' ? 0.025 : 0.018,
                r: type === 'death' ? 3 + Math.random() * 3 : 2 + Math.random() * 2,
                c: type === 'death' ? 'hsl(' + ((20 + Math.random() * 40) | 0) + ',90%,60%)' : '#7ED8F7',
                type
            });
        }
    }
    function updP() {
        for (let i = parts.length - 1; i >= 0; i--) {
            const p = parts[i];
            p.x += p.vx;
            p.y += p.vy;
            if (p.type !== 'bubble') p.vy += 0.04;
            p.life -= p.decay;
            if (p.life <= 0) parts.splice(i, 1);
        }
    }
    function drawP() {
        for (const p of parts) {
            ctx.globalAlpha = p.life * 0.7;
            ctx.fillStyle = p.c;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.r * p.life, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.globalAlpha = 1;
    }
    let state = 'menu',
        score = 0,
        hiScore = parseInt(localStorage.getItem('gooseHi')) || 0;
    let paused = false;
    let selSkin = parseInt(localStorage.getItem('gooseSkin')) || -1;
    let seenScore = parseInt(localStorage.getItem('gooseSeen')) || 0;
    let gameTime = 0,
        lastSpawn = 0,
        obstSpd = 2,
        spawnInt = 1400;
    let obsts = [],
        fc = 0,
        hitFlash = 0,
        shakeX = 0,
        shakeY = 0,
        overAlpha = 0;
    let goose = {x: W / 2, y: H * 0.75, w: 80, h: 64, bob: 0};
    let shield = false,
        shieldT = 0,
        bubItems = [],
        lastBub = 0,
        bubInt = 9000;
    const OBS_TYPES = [
        {type: 'shark', w: 56, h: 40, sw: 80, sh: 58},
        {type: 'croc', w: 52, h: 44, sw: 80, sh: 68},
        {type: 'stump', w: 36, h: 30, sw: 72, sh: 58},
        {type: 'rock', w: 38, h: 28, sw: 62, sh: 50}
    ];
    let tx0 = null,
        ty0 = null,
        gx0 = null,
        gy0 = null,
        drag = false;
    const keys = {};
    function pt(e) {
        const t = e.touches ? e.touches[0] : e,
            r = canvas.getBoundingClientRect();
        return {x: ((t.clientX - r.left) * W) / r.width, y: ((t.clientY - r.top) * H) / r.height};
    }
    function onDown(e) {
        if (e.preventDefault) e.preventDefault();
        const p = pt(e);
        if (state === 'menu') {
            if (p.x > W / 2 - 72 && p.x < W / 2 + 72 && p.y > H * 0.22 + TOP_O && p.y < H * 0.22 + 115 + TOP_O) {
                state = 'skins';
                seenScore = hiScore;
                localStorage.setItem('gooseSeen', seenScore);
                return;
            }
            if (p.y > H * 0.77 - 28 + TOP_O && p.y < H * 0.77 + 28 + TOP_O && p.x > W / 2 - 90 && p.x < W / 2 + 90) {
                startGame();
                return;
            }
            return;
        }
        if (state === 'skins') {
            handleSkinTap(p);
            return;
        }
        if (state === 'over') {
            if (p.y > H * 0.57 + TOP_O && p.y < H * 0.57 + 50 + TOP_O) {
                if (p.x > W / 2 - 100 && p.x < W / 2 - 6) {
                    state = 'menu';
                    paused = false;
                    return;
                }
                if (p.x > W / 2 + 6 && p.x < W / 2 + 100) {
                    onRetry?.();
                    startGame();
                    return;
                }
            }
            return;
        }
        tx0 = p.x;
        ty0 = p.y;
        gx0 = goose.x;
        gy0 = goose.y;
        drag = true;
        if (p.x > RR - 46 && p.x < RR + 6 && p.y > 8 + TOP_O && p.y < 56 + TOP_O) {
            paused = !paused;
            drag = false;
            return;
        }
        if (paused) {
            paused = false;
            return;
        }
    }
    function onMove(e) {
        if (e.preventDefault) e.preventDefault();
        if (!drag || state !== 'playing' || paused) return;
        const p = pt(e);
        goose.x = Math.max(RL + goose.w / 2, Math.min(RR - goose.w / 2, gx0 + (p.x - tx0)));
        goose.y = Math.max(goose.h / 2, Math.min(H - goose.h / 2, gy0 + (p.y - ty0)));
    }
    function onUp(e) {
        if (e.preventDefault) e.preventDefault();
        drag = false;
    }
    canvas.addEventListener('touchstart', onDown, {passive: false});
    canvas.addEventListener('touchmove', onMove, {passive: false});
    canvas.addEventListener('touchend', onUp, {passive: false});
    canvas.addEventListener('mousedown', onDown);
    canvas.addEventListener('mousemove', onMove);
    canvas.addEventListener('mouseup', onUp);
    document.addEventListener('keydown', e => {
        keys[e.key] = true;
        if ((e.key === ' ' || e.key === 'Enter') && state === 'menu') startGame();
        if (e.key === ' ' && state === 'playing') paused = !paused;
        if (e.key === 'Escape' && state === 'playing') paused = !paused;
        if (e.key === 'Escape' && state === 'skins') state = 'menu';
    });
    document.addEventListener('keyup', e => {
        keys[e.key] = false;
    });
    function startGame() {
        paused = false;
        state = 'playing';
        goose.x = W / 2;
        goose.y = H * 0.75;
        obsts = [];
        parts.splice(0);
        score = 0;
        gameTime = 0;
        lastSpawn = 0;
        hitFlash = 0;
        overAlpha = 0;
        shield = false;
        shieldT = 0;
        bubItems = [];
        lastBub = 0;
    }
    function spawnOb() {
        const n = Math.random() < 0.3 ? 2 : 1,
            used = [];
        for (let i = 0; i < n; i++) {
            const info = OBS_TYPES[(Math.random() * OBS_TYPES.length) | 0];
            let x,
                tries = 0;
            do {
                x = RL + info.w / 2 + Math.random() * (RW - info.w);
                tries++;
            } while (tries < 20 && used.some(px => Math.abs(px - x) < 64));
            if (n === 2 && used.length > 0 && !gapOk(used, x, info.w)) continue;
            used.push(x);
            const sw = info.type === 'shark' || info.type === 'croc';
            obsts.push({
                x,
                y: -info.h,
                w: info.w,
                h: info.h,
                type: info.type,
                sw: info.sw,
                sh: info.sh,
                wb: Math.random() * Math.PI * 2,
                swimAmp: sw ? 14 + Math.random() * 18 : 0,
                swimSpd: sw ? 0.02 + Math.random() * 0.015 : 0,
                baseX: x
            });
        }
    }
    function gapOk(pos, nx, nw) {
        const all = [...pos.map(px => ({x: px, w: 54})), {x: nx, w: nw}].sort(
            (a, b) => a.x - a.w / 2 - (b.x - b.w / 2)
        );
        let le = RL;
        for (const o of all) {
            if (o.x - o.w / 2 - le >= goose.w + 14) return true;
            le = Math.max(le, o.x + o.w / 2);
        }
        return RR - le >= goose.w + 14;
    }
    function checkHit(ob) {
        const hw = 28,
            hh = 20;
        return (
            goose.x - hw < ob.x + ob.w / 2 &&
            goose.x + hw > ob.x - ob.w / 2 &&
            goose.y - hh + goose.bob < ob.y + ob.h / 2 &&
            goose.y + hh + goose.bob > ob.y - ob.h / 2
        );
    }
    function getGameSpr() {
        let ai = -1;
        for (let i = SKIN_DEFS.length - 1; i >= 0; i--) {
            if (score >= SKIN_DEFS[i].score && SKIN_DEFS[i].img) {
                ai = i;
                break;
            }
        }
        const ui = ai > selSkin ? ai : selSkin;
        if (ui >= 0 && SKIN_DEFS[ui].img) return SKIN_DEFS[ui].img;
        return spr.goose;
    }
    function getMenuSpr() {
        if (selSkin >= 0 && SKIN_DEFS[selSkin].img && hiScore >= SKIN_DEFS[selSkin].score)
            return SKIN_DEFS[selSkin].img;
        return spr.goose;
    }
    let lt = 0,
        st = 0,
        _dt = 16;
    function update(ts) {
        const dt = lt ? ts - lt : 16;
        _dt = dt;
        lt = ts;
        updP();
        shakeX *= 0.85;
        shakeY *= 0.85;
        if (state !== 'playing') return;
        gameTime += dt;
        st += dt;
        if (st >= 1000) {
            score++;
            st -= 1000;
        }
        if (shield) {
            shieldT = Math.max(0, shieldT - dt);
            if (shieldT <= 0) {
                shield = false;
                shieldT = 0;
            }
        }
        const lv = (gameTime / 4000) | 0;
        obstSpd = 2.2 + lv * 0.18 + lv * lv * 0.012;
        spawnInt = Math.max(450, 1400 - lv * 80 - lv * lv * 3);
        const s = dt / 16;
        if (keys['ArrowLeft'] || keys['a']) goose.x = Math.max(RL + goose.w / 2, goose.x - 5 * s);
        if (keys['ArrowRight'] || keys['d']) goose.x = Math.min(RR - goose.w / 2, goose.x + 5 * s);
        if (keys['ArrowUp'] || keys['w']) goose.y = Math.max(goose.h / 2, goose.y - 5 * s);
        if (keys['ArrowDown'] || keys['s']) goose.y = Math.min(H - goose.h / 2, goose.y + 5 * s);
        if (gameTime - lastSpawn > spawnInt) {
            spawnOb();
            lastSpawn = gameTime;
        }
        if (gameTime - lastBub > bubInt && !shield) {
            bubItems.push({x: RL + 30 + Math.random() * (RW - 60), y: -20, r: 15});
            lastBub = gameTime;
            bubInt = 8000 + Math.random() * 6000;
        }
        if (fc % 16 === 0) emitP(goose.x + (Math.random() - 0.5) * 8, goose.y + 18, 'bubble', 1);
        for (let i = bubItems.length - 1; i >= 0; i--) {
            const b = bubItems[i];
            b.y += obstSpd * 0.55 * s;
            if (b.y > H + 30) {
                bubItems.splice(i, 1);
                continue;
            }
            const dx = goose.x - b.x,
                dy = goose.y + goose.bob - b.y;
            if (Math.sqrt(dx * dx + dy * dy) < b.r + goose.w / 3) {
                shield = true;
                shieldT = 15000;
                emitP(b.x, b.y, 'bubble', 10);
                bubItems.splice(i, 1);
            }
        }
        for (let i = obsts.length - 1; i >= 0; i--) {
            const ob = obsts[i];
            ob.y += obstSpd * s;
            if (ob.swimAmp) {
                ob.x = ob.baseX + Math.sin(fc * ob.swimSpd + ob.wb) * ob.swimAmp;
                ob.x = Math.max(RL + ob.w / 2, Math.min(RR - ob.w / 2, ob.x));
            }
            if (ob.y > H + 60) {
                obsts.splice(i, 1);
                continue;
            }
            if (checkHit(ob)) {
                if (shield) {
                    shield = false;
                    shieldT = 0;
                    shakeX = (Math.random() - 0.5) * 6;
                    shakeY = (Math.random() - 0.5) * 4;
                    emitP(goose.x, goose.y, 'death', 12);
                    obsts.splice(i, 1);
                    continue;
                }
                state = 'over';
                hitFlash = 20;
                shakeX = (Math.random() - 0.5) * 12;
                shakeY = (Math.random() - 0.5) * 7;
                emitP(goose.x, goose.y, 'death', 18);
                if (score > hiScore) {
                    hiScore = score;
                    localStorage.setItem('gooseHi', hiScore);
                }
                onGameOver?.();
                return;
            }
        }
    }
    function drawWater() {
        ctx.fillStyle = pal.riverBg;
        ctx.fillRect(RL, 0, RW, H);
        ctx.lineCap = 'round';
        for (let ly = 0; ly < 2; ly++) {
            const sp = [68, 95][ly],
                amp = [2.5, 3.5][ly],
                spd = [0.8, 0.5][ly];
            ctx.strokeStyle = 'rgba(255,255,255,' + (ly === 0 ? 0.11 : 0.07) + ')';
            ctx.lineWidth = 1.2;
            const sY = (fc * spd * 0.9) % sp;
            for (let y = -sp + sY; y < H; y += sp) {
                ctx.beginPath();
                for (let x = RL + 8; x <= RR - 8; x += 6) {
                    const yy = y + Math.sin((x + fc * spd * 0.4) * 0.025 + ly) * amp;
                    x === RL + 8 ? ctx.moveTo(x, yy) : ctx.lineTo(x, yy);
                }
                ctx.stroke();
            }
        }
        ctx.fillStyle = 'rgba(255,255,255,0.09)';
        for (let i = 0; i < 5; i++) {
            const sx = RL + 20 + ((i * 71 + fc * 0.28) % (RW - 40)),
                sy = (i * 117 + fc * 0.13) % H;
            ctx.beginPath();
            ctx.arc(sx, sy, 1.8 + Math.sin(fc * 0.025 + i) * 0.9, 0, Math.PI * 2);
            ctx.fill();
        }
    }
    function drawBanks() {
        for (let s = 0; s < 2; s++) {
            const bx = s === 0 ? 0 : RR;
            ctx.fillStyle = '#7EAE6E';
            ctx.fillRect(bx, 0, BANK, H);
            ctx.fillStyle = '#6A9E5A';
            const step = 15;
            const sY = (fc * 0.28) % step;
            for (let y = sY - step; y < H + step; y += step) {
                for (let x = 3; x < BANK - 3; x += 11) {
                    const gx = bx + x,
                        gy = y;
                    ctx.beginPath();
                    ctx.moveTo(gx, gy + 5);
                    ctx.quadraticCurveTo(gx - 3, gy + 1, gx, gy - 4);
                    ctx.quadraticCurveTo(gx + 3, gy + 1, gx + 1, gy + 5);
                    ctx.fill();
                }
            }
        }
    }
    function drawGoose(x, y) {
        const bob = Math.sin(fc * 0.07) * 2.5;
        goose.bob = bob;
        const gs = getGameSpr();
        if (!gs) return;
        goose.w = 80;
        goose.h = 64;
        if (shield) {
            const sr = 50,
                pulse = 1 + Math.sin(fc * 0.08) * 0.06;
            ctx.save();
            ctx.translate(x, y + bob);
            ctx.globalAlpha = 0.16 + Math.sin(fc * 0.06) * 0.05;
            ctx.fillStyle = '#7ED8F7';
            ctx.beginPath();
            ctx.arc(0, 0, sr * pulse, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 0.42 + Math.sin(fc * 0.06) * 0.1;
            ctx.strokeStyle = '#5EC4E8';
            ctx.lineWidth = 2.5;
            ctx.beginPath();
            ctx.arc(0, 0, sr * pulse, 0, Math.PI * 2);
            ctx.stroke();
            ctx.globalAlpha = 0.28;
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(-sr * 0.3, -sr * 0.32, sr * 0.11, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }
        ctx.drawImage(gs, x - 40, y - 32 + bob, 80, 64);
    }
    function drawBubItems() {
        for (let i = 0; i < bubItems.length; i++) {
            const b = bubItems[i],
                pulse = 1 + Math.sin(fc * 0.05 + i) * 0.1;
            ctx.save();
            ctx.translate(b.x, b.y);
            ctx.globalAlpha = 0.22;
            ctx.fillStyle = '#7ED8F7';
            ctx.beginPath();
            ctx.arc(0, 0, b.r * pulse, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 0.6;
            ctx.strokeStyle = '#5EC4E8';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.arc(0, 0, b.r * pulse, 0, Math.PI * 2);
            ctx.stroke();
            ctx.globalAlpha = 0.5;
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(-b.r * 0.28, -b.r * 0.32, b.r * 0.22, 0, Math.PI * 2);
            ctx.fill();
            ctx.restore();
        }
    }
    function drawBtn(x, y, w, h, txt) {
        ctx.fillStyle = pal.btnShadow;
        ctx.beginPath();
        rr(x + 2, y + 3, w, h, h / 2);
        ctx.fill();
        ctx.fillStyle = pal.btnPrimary;
        ctx.beginPath();
        rr(x, y, w, h, h / 2);
        ctx.fill();
        ctx.fillStyle = '#fff';
        ctx.font = 'bold ' + (w < 125 ? 15 : 18) + 'px ' + F;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(txt, x + w / 2, y + h / 2 + 1);
        ctx.textBaseline = 'alphabetic';
    }
    function drawCard(x, y, w, h, r) {
        ctx.fillStyle = 'rgba(120,155,175,0.08)';
        ctx.beginPath();
        rr(x + 2, y + 3, w, h, r);
        ctx.fill();
        ctx.fillStyle = pal.cardBg;
        ctx.beginPath();
        rr(x, y, w, h, r);
        ctx.fill();
    }
    function drawHUD() {
        const px = RL + 8,
            pw = RR - RL - 16;
        ctx.fillStyle = pal.hudBg;
        ctx.beginPath();
        rr(px, 10 + TOP_O, pw, 44, 16);
        ctx.fill();
        ctx.font = 'bold 11px ' + F;
        ctx.textAlign = 'left';
        ctx.fillStyle = pal.gold;
        ctx.fillText('BEST', px + 14, 24 + TOP_O);
        ctx.font = 'bold 18px ' + F;
        ctx.fillStyle = pal.textHint;
        ctx.fillText(hiScore, px + 14, 44 + TOP_O);
        ctx.font = 'bold 11px ' + F;
        ctx.textAlign = 'center';
        ctx.fillStyle = pal.btnPrimary;
        ctx.fillText('SCORE', W / 2, 24 + TOP_O);
        ctx.font = 'bold 18px ' + F;
        ctx.fillStyle = pal.textPrimary;
        ctx.fillText(score, W / 2, 44 + TOP_O);
        ctx.font = 'bold 18px ' + F;
        ctx.textAlign = 'right';
        ctx.fillStyle = pal.textPrimary;
        ctx.fillText(paused ? '▶' : '⏸', px + pw - 14, 38 + TOP_O);
        if (shield && shieldT > 0) {
            const sec = Math.ceil(shieldT / 1000);
            ctx.fillStyle = 'rgba(126,216,247,0.52)';
            ctx.beginPath();
            rr(W / 2 - 32, 60 + TOP_O, 64, 19, 9);
            ctx.fill();
            ctx.font = 'bold 11px ' + F;
            ctx.textAlign = 'center';
            ctx.fillStyle = pal.accent;
            ctx.fillText('\u{1F6E1}' + sec + 's', W / 2, 73 + TOP_O);
        }
    }
    const SKIN_SCORES: number[] = skinDefs.map(s => s.score);
    function drawPaused() {
        ctx.fillStyle = 'rgba(0,0,0,0.48)';
        ctx.fillRect(0, 0, W, H);
        ctx.fillStyle = pal.cardBg;
        ctx.beginPath();
        rr(W / 2 - 88, H / 2 - 72 + TOP_O, 176, 144, 22);
        ctx.fill();
        ctx.font = 'bold 22px ' + F;
        ctx.textAlign = 'center';
        ctx.fillStyle = pal.textPrimary;
        ctx.fillText('已暂停', W / 2, H / 2 - 32 + TOP_O);
        ctx.font = '13px ' + F;
        ctx.fillStyle = pal.textHint;
        ctx.fillText('点击任意处继续', W / 2, H / 2 - 6 + TOP_O);
        ctx.fillStyle = pal.btnPrimary;
        ctx.beginPath();
        rr(W / 2 - 54, H / 2 + 14 + TOP_O, 108, 42, 21);
        ctx.fill();
        ctx.font = 'bold 16px ' + F;
        ctx.fillStyle = '#fff';
        ctx.fillText('▶  继续', W / 2, H / 2 + 40 + TOP_O);
    }
    function handleSkinTap(p) {
        if (p.x > 18 && p.x < 74 && p.y > 18 + TOP_O && p.y < 50 + TOP_O) {
            state = 'menu';
            return;
        }
        const cols = 3,
            cw = 82,
            ch = 104,
            pad = 14,
            total = cols * cw + (cols - 1) * pad,
            sx0 = W / 2 - total / 2,
            sy0 = H * 0.17;
        for (let i = 0; i < 7; i++) {
            const col = i % cols,
                row = (i / cols) | 0,
                cx = sx0 + col * (cw + pad),
                cy = sy0 + row * (ch + pad + 4) + TOP_O;
            if (p.x >= cx && p.x <= cx + cw && p.y >= cy && p.y <= cy + ch) {
                const unlocked = i === 0 || hiScore >= SKIN_SCORES[i - 1];
                if (unlocked) {
                    selSkin = i - 1;
                    localStorage.setItem('gooseSkin', selSkin);
                }
                return;
            }
        }
    }
    function drawSkins() {
        drawWater();
        drawBanks();
        ctx.fillStyle = pal.overlayMed;
        ctx.fillRect(0, 0, W, H);
        drawCard(18, 18 + TOP_O, 54, 30, 12);
        ctx.font = 'bold 15px ' + F;
        ctx.textAlign = 'center';
        ctx.fillStyle = pal.textHint;
        ctx.fillText('\u2190', 45, 38 + TOP_O);
        ctx.font = '900 22px ' + F;
        ctx.textAlign = 'center';
        ctx.fillStyle = pal.titleColor;
        ctx.fillText('\u76ae\u80a4\u56fe\u9274', W / 2, 48 + TOP_O);
        const cols = 3,
            cw = 82,
            ch = 104,
            pad = 14,
            total = cols * cw + (cols - 1) * pad,
            sx0 = W / 2 - total / 2,
            sy0 = H * 0.17 + TOP_O;
        for (let i = 0; i < 7; i++) {
            const col = i % cols,
                row = (i / cols) | 0,
                cx = sx0 + col * (cw + pad),
                cy = sy0 + row * (ch + pad + 4);
            const unlocked = i === 0 || hiScore >= SKIN_SCORES[i - 1];
            const isSel = (i === 0 && selSkin === -1) || (i > 0 && selSkin === i - 1);
            if (isSel) {
                ctx.fillStyle = pal.btnAlpha;
                ctx.beginPath();
                rr(cx - 3, cy - 3, cw + 6, ch + 6, 15);
                ctx.fill();
                ctx.strokeStyle = pal.btnPrimary;
                ctx.lineWidth = 2.5;
                ctx.beginPath();
                rr(cx - 3, cy - 3, cw + 6, ch + 6, 15);
                ctx.stroke();
            }
            drawCard(cx, cy, cw, ch, 12);
            const sp = i === 0 ? spr.goose : SKIN_DEFS[i - 1].img;
            const is = 60,
                ix = cx + (cw - is) / 2,
                iy = cy + 6;
            if (unlocked) {
                if (sp) ctx.drawImage(sp, ix, iy, is, is);
            } else {
                ctx.fillStyle = 'rgba(200,210,222,0.35)';
                ctx.beginPath();
                rr(ix, iy, is, is, 10);
                ctx.fill();
                ctx.font = 'bold 30px ' + F;
                ctx.textAlign = 'center';
                ctx.fillStyle = 'rgba(100,120,145,0.5)';
                ctx.fillText('?', cx + cw / 2, iy + is / 2 + 11);
            }
            ctx.textAlign = 'center';
            if (!unlocked) {
                ctx.font = '400 10px ' + F;
                ctx.fillStyle = pal.textHint;
                ctx.fillText(SKIN_SCORES[i - 1] + '\u5206\u89e3\u9501', cx + cw / 2, cy + ch - 7);
            } else if (isSel) {
                ctx.font = 'bold 11px ' + F;
                ctx.fillStyle = pal.btnPrimary;
                ctx.fillText('\u2714 \u4f7f\u7528\u4e2d', cx + cw / 2, cy + ch - 7);
            } else if (i > 0) {
                ctx.font = '400 10px ' + F;
                ctx.fillStyle = pal.textHint;
                ctx.fillText(SKIN_DEFS[i - 1].name, cx + cw / 2, cy + ch - 7);
            }
        }
        ctx.font = '400 12px ' + F;
        ctx.textAlign = 'center';
        ctx.fillStyle = pal.hintAlpha;
        ctx.fillText('\u70b9\u51fb\u5df2\u89e3\u9501\u76ae\u80a4\u5373\u53ef\u88c5\u5907', W / 2, H * 0.92);
    }
    function drawMenu() {
        drawWater();
        drawBanks();
        ctx.fillStyle = pal.overlayFaint;
        ctx.fillRect(0, 0, W, H);
        drawCard(W / 2 - 122, H * 0.08 + TOP_O, 244, 78, 18);
        ctx.textAlign = 'center';
        ctx.font = '900 28px ' + F;
        ctx.fillStyle = pal.titleColor;
        ctx.fillText('\u9006\u6d41\u9e45\u4e0a', W / 2, H * 0.08 + 40 + TOP_O);
        ctx.font = '400 13px ' + F;
        ctx.fillStyle = pal.textHint;
        ctx.fillText('\u51b2\u7834\u6c34\u9006  \u6e38\u5411\u597d\u8fd0', W / 2, H * 0.08 + 62 + TOP_O);
        const ms = getMenuSpr();
        if (ms) {
            const bob = Math.sin(fc * 0.05) * 5;
            ctx.drawImage(ms, W / 2 - 72, H * 0.22 + bob + TOP_O, 144, 108);
            const hasNew = SKIN_DEFS.some(s => hiScore >= s.score && seenScore < s.score);
            ctx.globalAlpha = Math.sin(fc * 0.08) > 0 ? 1 : 0.55;
            ctx.font = 'bold 12px ' + F;
            ctx.textAlign = 'center';
            if (hasNew) {
                ctx.fillStyle = pal.gold;
                ctx.fillText(
                    '\u65b0\u76ae\u80a4\u5df2\u89e3\u9501\uff01\u70b9\u51fb\u67e5\u770b',
                    W / 2,
                    H * 0.22 + 128 + TOP_O
                );
            } else {
                ctx.fillStyle = pal.hintAlpha;
                ctx.fillText('\u70b9\u51fb\u67e5\u770b\u76ae\u80a4\u56fe\u9274', W / 2, H * 0.22 + 128 + TOP_O);
            }
            ctx.globalAlpha = 1;
        }
        const ty = H * 0.46 + TOP_O;
        drawCard(W / 2 - 132, ty, 264, 155, 16);
        ctx.textAlign = 'center';
        ctx.font = 'bold 12px ' + F;
        ctx.fillStyle = pal.textHint;
        ctx.fillText('\u6e38\u620f\u8bf4\u660e', W / 2, ty + 28);
        const lx = W / 2 - 98,
            is = 22;
        ctx.textAlign = 'left';
        ctx.font = '400 12px ' + F;
        ctx.fillStyle = pal.danger;
        ctx.fillText('\u907f\u5f00\u969c\u788d\u7269\uff1a', lx, ty + 52);
        let ix = lx + 84;
        if (spr.shark) {
            ctx.drawImage(spr.shark, ix, ty + 36, is * 1.4, is);
            ix += is * 1.4 + 5;
        }
        if (spr.croc) {
            ctx.drawImage(spr.croc, ix, ty + 36, is * 1.3, is);
            ix += is * 1.3 + 5;
        }
        if (spr.stump) {
            ctx.drawImage(spr.stump, ix, ty + 36, is, is);
            ix += is + 4;
        }
        if (spr.rock) {
            ctx.drawImage(spr.rock, ix, ty + 36, is, is);
        }
        ctx.fillStyle = '#3A9BC0';
        ctx.fillText('\u6536\u96c6\u6c14\u6ce1\uff1a', lx, ty + 80);
        const bx = lx + 74;
        ctx.save();
        ctx.globalAlpha = 0.22;
        ctx.fillStyle = '#7ED8F7';
        ctx.beginPath();
        ctx.arc(bx + 10, ty + 74, 10, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 0.6;
        ctx.strokeStyle = '#5EC4E8';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(bx + 10, ty + 74, 10, 0, Math.PI * 2);
        ctx.stroke();
        ctx.restore();
        ctx.fillStyle = pal.textHint;
        ctx.font = '400 11px ' + F;
        ctx.fillText('\u62b5\u6d88\u4e00\u6b21\u78b0\u649e', bx + 26, ty + 79);
        ctx.fillStyle = pal.gold;
        ctx.font = '400 12px ' + F;
        ctx.fillText('\u5206\u6570\u8d8a\u9ad8\u53ef\u89e3\u9501\u66f4\u591a\u76ae\u80a4', lx, ty + 106);
        ctx.textAlign = 'center';
        ctx.fillStyle = pal.hintAlpha;
        ctx.font = '400 11px ' + F;
        ctx.fillText('\u6ed1\u52a8\u5c4f\u5e55\u81ea\u7531\u79fb\u52a8', W / 2, ty + 145);
        const pulse = 1 + Math.sin(fc * 0.06) * 0.022;
        ctx.save();
        ctx.translate(W / 2, H * 0.77 + TOP_O);
        ctx.scale(pulse, pulse);
        drawBtn(-88, -27, 176, 54, '\u5f00\u59cb\u6e38\u620f');
        ctx.restore();
        if (fc % 10 === 0) emitP(RL + Math.random() * RW, H + 5, 'bubble', 1);
    }
    function drawGameOver() {
        overAlpha = Math.min(1, overAlpha + 0.04);
        ctx.fillStyle = 'rgba(184,216,232,' + overAlpha * 0.44 + ')';
        ctx.fillRect(0, 0, W, H);
        const cy = H * 0.2 + TOP_O;
        drawCard(W / 2 - 122, cy, 244, 228, 20);
        ctx.textAlign = 'center';
        ctx.font = '900 28px ' + F;
        ctx.fillStyle = pal.dangerLight;
        ctx.fillText('\u6e38\u620f\u7ed3\u675f', W / 2, cy + 58);
        ctx.fillStyle = pal.divider;
        ctx.fillRect(W / 2 - 55, cy + 70, 110, 1);
        ctx.font = '400 13px ' + F;
        ctx.fillStyle = pal.textHint;
        ctx.fillText('\u672c\u6b21\u5f97\u5206', W / 2, cy + 96);
        ctx.font = '900 44px ' + F;
        ctx.fillStyle = pal.textPrimary;
        ctx.fillText(score, W / 2, cy + 150);
        if (score > 0 && score >= hiScore) {
            ctx.font = 'bold 14px ' + F;
            ctx.fillStyle = pal.gold;
            ctx.fillText('\u{1F389} NEW RECORD!', W / 2, cy + 182);
        } else {
            ctx.font = '400 13px ' + F;
            ctx.fillStyle = pal.textMuted;
            ctx.fillText('\u6700\u9ad8\u5206 ' + hiScore, W / 2, cy + 182);
        }
        drawBtn(W / 2 - 100, H * 0.57 + TOP_O, 94, 48, '\u8fd4\u56de\u9996\u9875');
        drawBtn(W / 2 + 6, H * 0.57 + TOP_O, 94, 48, '\u518d\u6765\u4e00\u6b21');
    }
    function draw() {
        ctx.save();
        ctx.scale(scale, scale);
        ctx.fillStyle = pal.riverBg;
        ctx.fillRect(-10, -10, logicalW + 20, H + 20);
        ctx.translate(centreX + shakeX, shakeY);
        if (state === 'menu') {
            drawMenu();
        } else if (state === 'skins') {
            drawSkins();
        } else {
            drawWater();
            drawBanks();
            for (const ob of obsts) {
                const s = spr[ob.type];
                if (!s) continue;
                const sw = ob.type === 'shark' || ob.type === 'croc';
                const rot = sw ? Math.sin(fc * 0.06 + ob.wb) * 0.13 : 0;
                ctx.save();
                ctx.translate(ob.x, ob.y);
                ctx.rotate(rot);
                ctx.drawImage(s, -ob.sw / 2, -ob.sh / 2, ob.sw, ob.sh);
                ctx.restore();
            }
            drawBubItems();
            drawP();
            if (hitFlash > 0) {
                hitFlash--;
                if (hitFlash % 4 < 2) drawGoose(goose.x, goose.y);
            } else drawGoose(goose.x, goose.y);
            drawHUD();
            if (paused) drawPaused();
            if (state === 'over') drawGameOver();
        }
        ctx.restore();
    }
    let rafId = null;
    function loop(ts) {
        if (!paused) {
            fc++;
            update(ts);
        }
        draw();
        rafId = requestAnimationFrame(loop);
    }
    rafId = requestAnimationFrame(loop);
    return function () {
        if (rafId) cancelAnimationFrame(rafId);
        cancelAnimationFrame(correctionRafId);
        window.removeEventListener('resize', resize);
    };
}
